import sys

s = sys.stdin.readline().strip()
stack = []
pairs = {')': '(', ']': '[', '}': '{'}

for ch in s:
    if ch in '([{':
        stack.append(ch)
    elif not stack or stack.pop() != pairs.get(ch):
        print('false')
        break
else:
    print('true' if not stack else 'false')
